struct PairHash {
    template<typename A, typename B>
    std::size_t operator()(const std::pair<A, B>& p) const {
        auto h1 = std::hash<A>{}(p.first);
        auto h2 = std::hash<B>{}(p.second);
        return h1 ^ (h2 << 1);
    }
};
std::unordered_map<std::pair<int,int>, int, PairHash> grid_map;
